/**
 * @param {string} s
 * @return {number}
 */
function solve(s) {
    const freq = new Map();
    for (const char of s) {
        freq.set(char, (freq.get(char) || 0) + 1);
    }

    // Helper function to get the mirror character
    function getMirrorChar(c) {
        const code = c.charCodeAt(0);
        if (c >= 'a' && c <= 'z') {
            // Lowercase letters: 'a' (97) maps to 'z' (122), 'b' (98) maps to 'y' (121)
            // Mirror position: 25 - (original index)
            // Index of c: code - 'a'.charCodeAt(0)
            // Index of mirror: 25 - (code - 'a'.charCodeAt(0))
            // Mirror char code: 'z'.charCodeAt(0) - (code - 'a'.charCodeAt(0))
            const mirrorCharCode = 'z'.charCodeAt(0) - (code - 'a'.charCodeAt(0));
            return String.fromCharCode(mirrorCharCode);
        } else if (c >= '0' && c <= '9') {
            // Digits: '0' (48) maps to '9' (57), '1' (49) maps to '8' (56)
            // Mirror position: 9 - (original digit)
            // Digit value: code - '0'.charCodeAt(0)
            // Mirror digit value: 9 - (code - '0'.charCodeAt(0))
            // Mirror char code: '0'.charCodeAt(0) + (9 - (code - '0'.charCodeAt(0)))
            const mirrorCharCode = '0'.charCodeAt(0) + (9 - (code - '0'.charCodeAt(0)));
            return String.fromCharCode(mirrorCharCode);
        }
        return null; // Should not happen based on constraints
    }

    let totalDifference = 0;
    const processedPairs = new Set();

    // Iterate over all unique characters in the string
    for (const c of freq.keys()) {
        if (processedPairs.has(c)) {
            continue;
        }

        const m = getMirrorChar(c);

        if (m === null) {
            // Should not happen
            continue;
        }

        // Handle the case where c is its own mirror (e.g., 'm' <-> 'n' is not self-mirroring, 
        // but theoretically if c == m, we only calculate once)
        if (c === m) {
            // If c is its own mirror, we count its contribution here, and mark it as processed.
            // The difference |freq(c) - freq(m)| is |freq(c) - freq(c)| = 0.
            // We still need to mark it processed so we don't iterate over it again.
            totalDifference += 0;
            processedPairs.add(c);
            continue;
        }

        // Ensure we only process the pair (c, m) once, e.g., when c < m lexicographically, 
        // or based on some consistent ordering to prevent double counting (c, m) and (m, c).
        // Since we are iterating over keys, we rely on checking if 'm' has been processed or if 'c' is lexicographically smaller than 'm'.
        // A robust way is to use a canonical representation for the pair.
        const pairKey = c < m ? `${c},${m}` : `${m},${c}`;

        if (processedPairs.has(pairKey)) {
             // This check might be redundant if we only add the pair key once, but it's safer.
             continue;
        }

        // Calculate the absolute difference
        const freqC = freq.get(c);
        // If m is not in the string, freq(m) is 0
        const freqM = freq.get(m) || 0;
        const difference = Math.abs(freqC - freqM);

        totalDifference += difference;

        // Mark both characters as processed to ensure the pair (m, c) is skipped later
        processedPairs.add(c);
        processedPairs.add(m);
    }

    return totalDifference;
}

