import java.util.HashMap;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;

class Solution {
    public static long solve(String s) {
        Map<Character, Integer> freq = new HashMap<>();
        for (char c : s.toCharArray()) {
            freq.put(c, freq.getOrDefault(c, 0) + 1);
        }

        // Helper function to get the mirror character
        java.util.function.Function<Character, Character> getMirrorChar = (c) -> {
            char mirror = ' ';
            if (c >= 'a' && c <= 'z') {
                // Lowercase letters: 'a' (97) maps to 'z' (122), 'b' (98) maps to 'y' (121)
                // Mirror char code = 'z'.charCodeAt(0) - (c.charCodeAt(0) - 'a'.charCodeAt(0))
                int mirrorCharCode = 'z' - (c - 'a');
                mirror = (char) mirrorCharCode;
            } else if (c >= '0' && c <= '9') {
                // Digits: '0' (48) maps to '9' (57), '1' (49) maps to '8' (56)
                // Mirror digit value = 9 - (c - '0')
                int mirrorDigitValue = 9 - (c - '0');
                // Mirror char code = '0'.charCodeAt(0) + mirrorDigitValue
                mirror = (char) ('0' + mirrorDigitValue);
            }
            return mirror;
        };

        long totalDifference = 0;
        Set<Character> processed = new HashSet<>();

        // Iterate over all unique characters in the string
        for (char c : freq.keySet()) {
            if (processed.contains(c)) {
                continue;
            }

            char m = getMirrorChar.apply(c);

            if (m == ' ') {
                // Should not happen based on constraints
                continue;
            }

            // Calculate the absolute difference
            int freqC = freq.get(c);
            // If m is not in the string, freq(m) is 0
            int freqM = freq.getOrDefault(m, 0);

            long difference = Math.abs(freqC - freqM);

            if (c == m) {
                // If c is its own mirror, we add the difference (which is 0) and mark processed.
                totalDifference += difference;
                processed.add(c);
            } else {
                // To avoid double counting (c, m) and (m, c), we only process the pair if c is lexicographically smaller than m.
                if (c < m) {
                    totalDifference += difference;
                    // Mark both as processed
                    processed.add(c);
                    processed.add(m);
                } 
                // If c > m, the pair (m, c) would have been processed when the loop reached m.
                // If c == m, it is handled above.
            }
        }

        return totalDifference;
    }
}
